  1→#!/usr/bin/env bun
  2→
  3→/**
  4→ * Ralph Loop - Automated Claude Code Task Executor
  5→ *
  6→ * Based on Geoffrey Huntley's Ralph Wiggum technique:
  7→ * - Fresh context per iteration (new Claude instance each time)
  8→ * - Memory persists through files only (git, progress.txt)
  9→ * - One task per iteration
 10→ * - Completion signal terminates loop
 11→ *
 12→ * Uses Claude CLI's --output-format stream-json for real-time streaming.
 13→ *
 14→ * @see https://ghuntley.com/ralph/
 15→ */
 16→
 17→import { appendFileSync, mkdirSync, renameSync } from 'node:fs';
 18→import { chalk } from 'zx';
 19→import {
 20→  AsyncSeriesHook,
 21→  SyncHook,
 22→  SyncWaterfallHook,
 23→  SyncBailHook,
 24→} from 'tapable';
 25→
 26→const ANSI_REGEX = /\x1B\[[0-9;]*m/g;
 27→const stripAnsi = (s: string): string => s.replace(ANSI_REGEX, '');
 28→
 29→function parsePositiveInt(arg: string | undefined, fallback: number): number {
 30→  const parsed = parseInt(arg ?? String(fallback), 10);
 31→  if (isNaN(parsed) || parsed <= 0) {
 32→    console.error(`Error: expected a positive integer, got "${arg}"`);
 33→    process.exit(1);
 34→  }
 35→  return parsed;
 36→}
 37→
 38→const LOG_DIR = './.loop';
 39→mkdirSync(LOG_DIR, { recursive: true });
 40→
 41→const CONFIG = Object.freeze({
 42→  maxIterations: parsePositiveInt(Bun.argv[2], 100),
 43→  delayBetweenIterations: 1_000,
 44→  progressFile: './.claude/progress.txt',
 45→  iterationTimeout: 600_000,
 46→  logFlushInterval: 2_000,
 47→  exitPattern: /RALPH_STATUS:\s*\{[^}]*"exit":\s*true[^}]*\}/,
 48→});
 49→
 50→interface IterationContext {
 51→  iteration: number;
 52→  maxIterations: number;
 53→  logPath: string;
 54→}
 55→
 56→interface FailureContext extends IterationContext {
 57→  exitCode: number;
 58→  consecutiveFailures: number;
 59→}
 60→
 61→interface BackoffContext extends FailureContext {
 62→  backoffMs: number;
 63→}
 64→
 65→const hooks = {
 66→  loopStart: new AsyncSeriesHook<[typeof CONFIG]>(['config']),
 67→  iterationStart: new AsyncSeriesHook<[IterationContext]>(['context']),
 68→  iterationSuccess: new AsyncSeriesHook<[IterationResult, IterationContext]>([
 69→    'result',
 70→    'context',
 71→  ]),
 72→  iterationTimeout: new SyncHook<[IterationResult, IterationContext]>([
 73→    'result',
 74→    'context',
 75→  ]),
 76→  iterationFailure: new AsyncSeriesHook<[IterationResult, FailureContext]>([
 77→    'result',
 78→    'context',
 79→  ]),
 80→  statusParsed: new SyncWaterfallHook<[RalphStatus | null, string]>([
 81→    'status',
 82→    'output',
 83→  ]),
 84→  taskComplete: new AsyncSeriesHook<[RalphStatus, IterationContext]>([
 85→    'status',
 86→    'context',
 87→  ]),
 88→  allTasksComplete: new AsyncSeriesHook<[RalphStatus, number]>([
 89→    'status',
 90→    'totalIterations',
 91→  ]),
 92→  backoff: new SyncBailHook<[BackoffContext], boolean>(['context']),
 93→  loopEnd: new SyncHook<[number]>(['totalIterations']),
 94→  cleanup: new SyncHook<[string]>(['signal']),
 95→};
 96→
 97→export { hooks as ralphHooks };
