177→type Color = 'green' | 'yellow' | 'red' | 'blue' | 'blackBright';
178→
179→function print(message: string, color?: Color): void {
180→  const colored = color ? chalk[color](message) : message;
181→  process.stdout.write(colored);
182→  logBuffer.write(message);
183→}
184→
185→function println(message = '', color?: Color): void {
186→  const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);
187→  print(`[${ts}] ${message}\n`, color);
188→}
189→
190→function syslog(message = '', color?: Color): void {
191→  println(`‣ ${message}`, color);
192→}
